1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	function basePremium(item: any): number {
21	  return BASE_PREMIUMS[item.type] ?? 0;
22	}
23	
24	export function claimOffice(input: any): unknown {
25	  const results = [];
26	  for (const step of input.steps) {
27	    validateItemTypes(step.items);
28	    let premium = PROCESSING_FEE;
29	    for (const item of step.items) {
30	      premium += basePremium(item);
31	    }
32	    results.push({ premium });
33	  }
34	  return { results };
35	}
